  private bindNavigation(host:HTMLElement):void {let panning=false,last={x:0,y:0};host.oncontextmenu=e=>{if(e.button===1)e.preventDefault()};host.onpointerdown=e=>{if(e.button===0)this.unpinFocus();if((e.button===0&&!this.dragged)||e.button===1){e.preventDefault();panning=true;last={x:e.clientX,y:e.clientY};host.setPointerCapture(e.pointerId)}};host.onpointermove=e=>{const rect=host.getBoundingClientRect();if(this.hovered){const gx=(e.clientX-rect.left-this.offset.x)/this.scale,gy=(e.clientY-rect.top-this.offset.y)/this.scale,r=this.hovered.radius*this.plugin.settings.display.nodeSize+6/this.scale;if(Math.hypot(gx-this.hovered.x,gy-this.hovered.y)>r)this.clearHover()}if(this.dragged&&(e.buttons&1)){panning=false;const x=(e.clientX-rect.left-this.offset.x)/this.scale,y=(e.clientY-rect.top-this.offset.y)/this.scale;this.dragged.x=x;this.dragged.y=y;this.worker?.postMessage({type:"drag",id:this.dragged.id,x,y});this.queueRender();return}if(!panning)return;this.zoomTarget=undefined;this.offset.x+=e.clientX-last.x;this.offset.y+=e.clientY-last.y;last={x:e.clientX,y:e.clientY};this.applyCameraTransform()};host.onpointerup=e=>{if(e.button===0||e.button===1)panning=false;if(e.button===0)this.releaseNode()};host.onpointerleave=()=>{panning=false;this.cancelHoverIntent();this.releaseNode();this.clearHover()};host.onwheel=e=>{e.preventDefault();this.clearHoverImmediate();const rect=host.getBoundingClientRect(),px=e.clientX-rect.left,py=e.clientY-rect.top,target=Math.max(.08,Math.min(5,(this.zoomTarget?.scale??this.scale)*Math.exp(-e.deltaY*.001)));const base=this.zoomTarget??{scale:this.scale,x:this.offset.x,y:this.offset.y},gx=(px-base.x)/base.scale,gy=(py-base.y)/base.scale;this.zoomTarget={scale:target,x:px-gx*target,y:py-gy*target};this.animateZoom()};}
