  private scheduleModelRefresh():void {if(this.modelRefreshTimer)window.clearTimeout(this.modelRefreshTimer);this.modelRefreshTimer=window.setTimeout(()=>{this.modelRefreshTimer=undefined;for(const n of this.model.nodes)this.plugin.data.positions[n.path]={x:n.x,y:n.y};this.rebuild(true);this.createPanels();this.updateBreadcrumb();this.updateGraphCount()},350)}
  private autoTuneDisplay():void {const count=Math.max(1,this.model.nodes.filter(n=>n.visible).length),area=Math.max(1,this.contentEl.clientWidth*this.contentEl.clientHeight),density=Math.max(.65,Math.min(1.45,Math.sqrt((count/1430)*(2073600/area))));this.plugin.settings.display={...this.plugin.settings.display,textFade:Math.round(Math.max(14,Math.min(40,DEFAULT_DISPLAY.textFade*Math.sqrt(density)))),nodeSize:Number(Math.max(.45,Math.min(1.2,DEFAULT_DISPLAY.nodeSize/Math.sqrt(density))).toFixed(2)),linkThickness:Number(Math.max(.4,Math.min(1.4,DEFAULT_DISPLAY.linkThickness/Math.sqrt(density))).toFixed(2)),glow:DEFAULT_DISPLAY.glow,glowSize:DEFAULT_DISPLAY.glowSize};this.invalidateNodeStyles();this.updateNodeScale();void this.plugin.persistData();this.renderGraph()}
