  private fit():void {const nodes=this.model.nodes.filter(n=>n.visible&&Number.isFinite(n.x)&&Number.isFinite(n.y));if(!nodes.length)return;let minX=Infinity,maxX=-Infinity,minY=Infinity,maxY=-Infinity;for(const n of nodes){minX=Math.min(minX,n.x);maxX=Math.max(maxX,n.x);minY=Math.min(minY,n.y);maxY=Math.max(maxY,n.y)}const width=Math.max(100,maxX-minX),height=Math.max(100,maxY-minY),availableW=Math.max(300,this.contentEl.clientWidth-560),availableH=Math.max(250,this.contentEl.clientHeight-180),scale=Math.max(.06,Math.min(1.25,availableW/width,availableH/height)*.9);this.zoomTarget={scale,x:this.contentEl.clientWidth/2-(minX+maxX)/2*scale,y:this.contentEl.clientHeight/2-(minY+maxY)/2*scale};this.animateZoom();}
  private showTooltip(n:GraphNode):void {let tip=this.contentEl.querySelector<HTMLElement>(".beautiful-graph-tooltip");if(!tip)tip=this.contentEl.createDiv({cls:"beautiful-graph-tooltip"});tip.empty();tip.createDiv({cls:"beautiful-tooltip-title",text:n.label});tip.createDiv({cls:"beautiful-tooltip-meta",text:`${n.category} · ${n.degree} connections`});const path=tip.createDiv({cls:"beautiful-tooltip-path",text:formatTooltipPath(n.path)});path.title=this.prettyPath(n.path);if(n.description)tip.createDiv({cls:"beautiful-tooltip-description",text:n.description});tip.show();}
